export enum Category {
  PAINTING = 'Painting',
  DRAWING = 'Drawing',
  DIGITAL = 'Digital',
  SCULPTURE = 'Sculpture',
  ALL = 'All'
}

export interface Artwork {
  id: string;
  title: string;
  category: Category;
  year: string;
  medium: string;
  dimensions: string;
  description: string;
  imageUrl: string;
  aiInsight?: string;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { Artwork } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getArtworkAnalysis = async (artwork: Artwork) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this artwork titled "${artwork.title}". 
      Category: ${artwork.category}, Medium: ${artwork.medium}. 
      Description: ${artwork.description}.
      Provide a sophisticated "Art Critic" style interpretation (max 100 words).`,
    });
    return response.text;
  } catch (error) {
    console.error("Error analyzing artwork:", error);
    return "Analysis unavailable at this moment.";
  }
};

export const chatWithAssistant = async (history: { role: string; parts: { text: string }[] }[], message: string) => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: "You are the personal studio assistant for Andrew Ferrari, a world-class contemporary artist. You are polite, knowledgeable about art history, and deeply familiar with Andrew's portfolio. Andrew's style is characterized by emotional depth, a mix of abstract and representational forms, and a sophisticated use of texture. Answer questions about his work, inspirations, and techniques with elegance and insight.",
      }
    });

    // In this SDK version, history is handled slightly differently in create, but we can just use sendMessage
    const response = await chat.sendMessage({ message });
    return response.text;
  } catch (error) {
    console.error("Error in chat:", error);
    return "I'm sorry, I'm having trouble connecting to the studio archives.";
  }
};

export const analyzeUploadedImage = async (base64Data: string, mimeType: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: "Describe this artwork in detail. Suggest a title, category (Painting, Drawing, Digital, or Sculpture), medium, and an artistic description. Format as JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Error analyzing image:", error);
    throw error;
  }
};

