import { GoogleGenAI } from "@google/genai";
import { Artwork } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getArtworkAnalysis = async (artwork: Artwork) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `다음 작품에 대해 한국어로 분석해 주세요. 제목: "${artwork.title}". 
      카테고리: ${artwork.category}, 매체: ${artwork.medium}. 
      설명: ${artwork.description}.
      전문적인 "미술 비평가" 스타일의 세련된 해석을 제공해 주세요 (최대 150자).`,
    });
    return response.text;
  } catch (error) {
    console.error("Error analyzing artwork:", error);
    return "현재 분석을 제공할 수 없습니다.";
  }
};

export const chatWithAssistant = async (history: { role: string; parts: { text: string }[] }[], message: string) => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: "당신은 세계적인 현대 미술가 앤드류 페라리(Andrew Ferrari)의 개인 스튜디오 어시스턴트입니다. 당신은 정중하고 미술사에 해박하며, 앤드류의 포트폴리오를 깊이 이해하고 있습니다. 앤드류의 스타일은 감정적 깊이, 추상과 구상의 혼합, 세련된 질감 사용이 특징입니다. 그의 작품, 영감, 기법에 대한 질문에 품격 있고 통찰력 있게 한국어로 답변해 주세요.",
      }
    });

    const response = await chat.sendMessage({ message });
    return response.text;
  } catch (error) {
    console.error("Error in chat:", error);
    return "죄송합니다. 현재 스튜디오 아카이브에 연결하는 데 문제가 발생했습니다.";
