export const analyzeUploadedImage = async (base64Data: string, mimeType: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: "이 작품을 자세히 설명해 주세요. 제목, 카테고리(Painting, Drawing, Digital, Sculpture 중 하나), 매체, 그리고 예술적 설명을 제안해 주세요. 모든 텍스트는 한국어로 작성하고 JSON 형식으로 응답해 주세요." }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Error analyzing image:", error);
    throw error;
  }
};

