const AssistantChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: "앤드류 페라리 스튜디오에 오신 것을 환영합니다. 저는 디지털 큐레이터입니다. 작가의 작품 세계에 대해 궁금한 점이 있으신가요?" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMessage = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsTyping(true);

    const response = await chatWithAssistant(
      messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })),
      userMessage
    );

    setIsTyping(false);
    setMessages(prev => [...prev, { role: 'model', text: response || "현재 연결에 문제가 있습니다. 잠시 후 다시 시도해 주세요." }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[200]">
      {isOpen ? (
        <div className="bg-white w-80 md:w-96 h-[500px] shadow-2xl rounded-2xl flex flex-col border border-gray-100 overflow-hidden transition-all duration-300 transform scale-100 origin-bottom-right">
